const ticket = $input.first().json.body || $input.first().json;
const subject = (ticket.subject || '').toLowerCase();
const body = (ticket.body || ticket.message || '').toLowerCase();
const text = `${subject} ${body}`;

let category = 'General';
let department = 'Support';
let priority = 'medium';

if (/billing|payment|invoice|refund/.test(text)) {
  category = 'Billing';
  department = 'Finance';
  priority = 'high';
} else if (/bug|error|crash|broken|not working/.test(text)) {
  category = 'Technical';
  department = 'Engineering';
  priority = 'high';
} else if (/feature|request|enhancement/.test(text)) {
  category = 'Feature Request';
  department = 'Product';
  priority = 'low';
}

return [{
  json: {
    ticketId: ticket.ticketId || `TKT-${Date.now()}`,
    subject: ticket.subject || 'No subject',
    category,
    department,
    priority,
    assignedTo: `${department} Team`,
    slackMessage: `🎫 New ${category} ticket → ${department} (${priority} priority)\nSubject: ${ticket.subject || 'N/A'}`
  }
}];

const data = $input.first().json;
return [{
  json: {
    ...data,
    departmentAssigned: true,
    assignedAt: new Date().toISOString()
  }
}];

const data = $input.first().json;
return [{
  json: {
    ...data,
    slackNotified: true,
    notification: data.slackMessage
  }
}];
